import{_ as a,C as d,o as r,c as s,E as n,a3 as o}from"./chunks/framework.DelMn36m.js";const i="/versions/v0.9.0/screens/devices/step-seq.png",h="/versions/v0.9.0/screens/devices/step-seq-step-params.png",v=JSON.parse('{"title":"Step Seq","description":"","frontmatter":{"title":"Step Seq","pageClass":"device-doc"},"headers":[],"relativePath":"devices/step-seq.md","filePath":"devices/step-seq.md"}'),l={name:"devices/step-seq.md"};function g(c,t,p,m,b,u){const e=d("DeviceHeading");return r(),s("div",null,[n(e,{slug:"step-seq",title:"Step Seq"}),t[0]||(t[0]=o('<p>Classic clock-synced step sequencer</p><p><img src="'+i+'" alt="Step Seq parameters" class="screen"></p><h2 id="when-to-use-it" tabindex="-1">When to use it <a class="header-anchor" href="#when-to-use-it" aria-label="Permalink to &quot;When to use it&quot;">​</a></h2><p>Add <strong>Step Seq</strong> after a <strong>Clock</strong> when you want a classic <strong>4–16 step sequencer</strong> you edit on a full-screen grid — notes with velocity and gate, or stepped writes to another device parameter.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Needs clock (internal or external). Unlike most devices, Step Seq opens a <strong>custom step grid</strong> instead of a plain parameter list.</p></div><h2 id="editing-the-grid" tabindex="-1">Editing the grid <a class="header-anchor" href="#editing-the-grid" aria-label="Permalink to &quot;Editing the grid&quot;">​</a></h2><p>Step Seq opens a <strong>full-width step grid</strong> (not the usual parameter list):</p><table tabindex="0"><thead><tr><th>Control</th><th>On the grid</th><th>On the settings slot</th></tr></thead><tbody><tr><td>Encoder</td><td>Move focus across steps → settings icon</td><td>—</td></tr><tr><td>Select</td><td>Toggle the focused step <strong>Active</strong></td><td>Open <strong>settings</strong> (device parameters)</td></tr><tr><td>Hold Select + encoder</td><td>Edit <strong>Note</strong> (Note mode) or <strong>Value</strong> (Param mode)</td><td>—</td></tr><tr><td>Select + Back</td><td>Open the <strong>per-step parameter</strong> list on the left</td><td>Open <strong>settings</strong> on the left</td></tr><tr><td>Back</td><td>—</td><td>Close the left panel and return to the grid</td></tr></tbody></table><p>Filled steps show a <strong>velocity bar</strong>; a triangle marks the <strong>playhead</strong>. Note names (or param values) sit under each cell.</p><p><img src="'+h+'" alt="Step Seq per-step parameters" class="screen"></p><h2 id="settings-parameters" tabindex="-1">Settings parameters <a class="header-anchor" href="#settings-parameters" aria-label="Permalink to &quot;Settings parameters&quot;">​</a></h2><div class="device-params-table"><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Bypass</td><td>0 – 1</td><td>When on, the device is disabled and MIDI passes through unchanged.</td></tr><tr><td>Steps</td><td>4 – 16</td><td>Number of steps in the pattern (4–16).</td></tr><tr><td>Rate</td><td>0 – 6</td><td>Clock division for each step advance.</td></tr><tr><td>Mode</td><td>0 – 1</td><td>What each active step emits: MIDI notes, or writes to a targeted device parameter.</td></tr><tr><td>Seq Ch</td><td>0 – 16</td><td>Default MIDI channel for note output (Global follows the project global channel).</td></tr><tr><td>Direction</td><td>0 – 2</td><td>How the playhead walks the step ring: forward, reverse, or ping-pong.</td></tr><tr><td>Randomize</td><td>0 – 1</td><td>Momentary action — randomizes active steps using Rand Depth.</td></tr><tr><td>Rand Depth</td><td>0 – 100</td><td>How aggressively Randomize rewrites step fields (0–100%).</td></tr></tbody></table></div><h2 id="per-step-parameters" tabindex="-1">Per-step parameters <a class="header-anchor" href="#per-step-parameters" aria-label="Permalink to &quot;Per-step parameters&quot;">​</a></h2><p>These fields are <strong>per step</strong> (not in the settings list). Open them with <strong>Select + Back</strong> on a focused step. LFO, knob-macro, and external mappings can target a step field with that step’s index.</p><h3 id="note-mode" tabindex="-1">Note mode <a class="header-anchor" href="#note-mode" aria-label="Permalink to &quot;Note mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Active</td><td>0 – 1</td><td>Whether the step fires when the playhead lands on it.</td></tr><tr><td>Note</td><td>0 – 127</td><td>MIDI note number for this step.</td></tr><tr><td>Velocity</td><td>1 – 127</td><td>Note-on velocity (also drawn as the cell bar height).</td></tr><tr><td>Gate</td><td>10 – 200</td><td>Note length as a percentage of the step.</td></tr><tr><td>Channel</td><td>0 – 16</td><td>Per-step channel override (<strong>Global</strong> uses <strong>Seq Ch</strong>).</td></tr><tr><td>Probability</td><td>0 – 100</td><td>Chance the step fires when active (0–100%).</td></tr></tbody></table><h3 id="param-mode" tabindex="-1">Param mode <a class="header-anchor" href="#param-mode" aria-label="Permalink to &quot;Param mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Parameter</th><th>Range</th><th>What it does</th></tr></thead><tbody><tr><td>Active</td><td>0 – 1</td><td>Whether the step writes when the playhead lands on it.</td></tr><tr><td>Value</td><td>target min – max</td><td>Value scaled into the sequence’s parameter target range.</td></tr><tr><td>Probability</td><td>0 – 100</td><td>Chance the step writes when active (0–100%).</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>Mode</strong>, <strong>Steps</strong>, <strong>Rate</strong>, <strong>Seq Ch</strong>, <strong>Direction</strong>, and <strong>Randomize</strong> live in <strong>settings</strong> (settings icon on the grid, or Select + Back on the settings slot).</p></div><h2 id="parameter-values" tabindex="-1">Parameter values <a class="header-anchor" href="#parameter-values" aria-label="Permalink to &quot;Parameter values&quot;">​</a></h2><h3 id="bypass" tabindex="-1">Bypass <a class="header-anchor" href="#bypass" aria-label="Permalink to &quot;Bypass&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Device is active and processes MIDI.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Device is bypassed; messages pass through unchanged.</td></tr></tbody></table><h3 id="rate" tabindex="-1">Rate <a class="header-anchor" href="#rate" aria-label="Permalink to &quot;Rate&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>1/1</td><td>One note per bar (quarter-note grid).</td></tr><tr><td style="text-align:right;">1</td><td>1/2</td><td>Half-note steps.</td></tr><tr><td style="text-align:right;">2</td><td>1/4</td><td>Quarter-note steps.</td></tr><tr><td style="text-align:right;">3</td><td>1/8</td><td>Eighth-note steps.</td></tr><tr><td style="text-align:right;">4</td><td>1/16</td><td>Sixteenth-note steps.</td></tr><tr><td style="text-align:right;">5</td><td>1/32</td><td>Thirty-second-note steps.</td></tr><tr><td style="text-align:right;">6</td><td>1/64</td><td>Sixty-fourth-note steps.</td></tr></tbody></table><h3 id="mode" tabindex="-1">Mode <a class="header-anchor" href="#mode" aria-label="Permalink to &quot;Mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Note</td><td>Active steps emit MIDI notes (note, velocity, gate, channel, probability).</td></tr><tr><td style="text-align:right;">1</td><td>Param</td><td>Active steps write a scaled value to the sequence&#39;s parameter target.</td></tr></tbody></table><h3 id="seq-ch" tabindex="-1">Seq Ch <a class="header-anchor" href="#seq-ch" aria-label="Permalink to &quot;Seq Ch&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Global</td><td>Use the project global MIDI channel when a step has no override.</td></tr><tr><td style="text-align:right;">1</td><td>Ch1</td><td>Force note output to MIDI channel 1 (Ch2–Ch16 work the same way).</td></tr></tbody></table><h3 id="direction" tabindex="-1">Direction <a class="header-anchor" href="#direction" aria-label="Permalink to &quot;Direction&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Fwd</td><td>Playhead advances 0 → last step, then wraps.</td></tr><tr><td style="text-align:right;">1</td><td>Rev</td><td>Playhead walks last → 0, then wraps.</td></tr><tr><td style="text-align:right;">2</td><td>PingPong</td><td>Playhead reverses direction at each end.</td></tr></tbody></table><h3 id="randomize" tabindex="-1">Randomize <a class="header-anchor" href="#randomize" aria-label="Permalink to &quot;Randomize&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:right;">Value</th><th>Name</th><th>Meaning</th></tr></thead><tbody><tr><td style="text-align:right;">0</td><td>Off</td><td>Idle — press Select on Randomize to fire once.</td></tr><tr><td style="text-align:right;">1</td><td>On</td><td>Triggers a one-shot randomize of the pattern.</td></tr></tbody></table>',32))])}const x=a(l,[["render",g]]);export{v as __pageData,x as default};
